using System.ComponentModel.DataAnnotations;

namespace sv_7ff94ea9047144eb9ea135bc3f58403f.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;
}

using sv_7ff94ea9047144eb9ea135bc3f58403f.Models;

namespace sv_7ff94ea9047144eb9ea135bc3f58403f.Services;

public class InventoryService
{
    private readonly Lock _lock = new();
    private readonly List<Product> _products;
    private int _nextId;

    public InventoryService()
    {
        _products = new List<Product>
        {
            new() { Id = 1, Name = "Wireless Mouse", Quantity = 150, UnitPrice = 29.99m, Category = "Electronics" },
            new() { Id = 2, Name = "Cotton T-Shirt", Quantity = 300, UnitPrice = 14.50m, Category = "Clothing" },
            new() { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 12.99m, Category = "Food" },
            new() { Id = 4, Name = "USB-C Cable", Quantity = 500, UnitPrice = 9.99m, Category = "Electronics" },
            new() { Id = 5, Name = "Winter Jacket", Quantity = 45, UnitPrice = 89.95m, Category = "Clothing" },
            new() { Id = 6, Name = "Granola Bars (12-pack)", Quantity = 200, UnitPrice = 6.49m, Category = "Food" },
        };
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList());
        }
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == product.Id);
            if (existing is not null)
            {
                existing.Name = product.Name;
                existing.Quantity = product.Quantity;
                existing.UnitPrice = product.UnitPrice;
                existing.Category = product.Category;
            }
        }
        return Task.CompletedTask;
    }

    public Task<Product> AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(new Product
            {
                Id = product.Id,
                Name = product.Name,
                Quantity = product.Quantity,
                UnitPrice = product.UnitPrice,
                Category = product.Category
            });
        }
        return Task.FromResult(product);
    }
}

@page "/inventory"
@using sv_7ff94ea9047144eb9ea135bc3f58403f.Models
@using sv_7ff94ea9047144eb9ea135bc3f58403f.Services
@inject InventoryService InventoryService
@inject NavigationManager Navigation

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@* MODE 1 — Static SSR Quick Add form *@
<div class="card mb-4">
    <div class="card-header">Quick Add Product</div>
    <div class="card-body">
        <EditForm Model="NewProduct" FormName="QuickAdd" method="post" OnValidSubmit="HandleAdd" Enhance>
            <DataAnnotationsValidator />
            <ValidationSummary />
            <div class="row g-2 align-items-end">
                <div class="col-md-3">
                    <label class="form-label">Name</label>
                    <InputText class="form-control" @bind-Value="NewProduct.Name" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.Quantity" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Unit Price</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.UnitPrice" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Category</label>
                    <InputSelect class="form-select" @bind-Value="NewProduct.Category">
                        <option value="">-- Select --</option>
                        <option value="Electronics">Electronics</option>
                        <option value="Clothing">Clothing</option>
                        <option value="Food">Food</option>
                        <option value="Other">Other</option>
                    </InputSelect>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary w-100">Add</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

@* Product table with inline editing *@
<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Quantity</th>
            <th>Unit Price</th>
            <th>Category</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @if (Products is not null)
        {
            @foreach (var product in Products)
            {
                @if (EditingProductId == product.Id)
                {
                    @* MODE 2 — Interactive edit row rendered with InteractiveServer *@
                    <EditRow Product="product"
                             OnSave="HandleSave"
                             OnCancel="HandleCancel"
                             @rendermode="InteractiveServer" />
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <a href="/inventory?edit=@product.Id" class="btn btn-sm btn-outline-secondary">Edit</a>
                        </td>
                    </tr>
                }
            }
        }
    </tbody>
</table>

@code {
    [SupplyParameterFromForm]
    private Product NewProduct { get; set; } = new();

    [SupplyParameterFromQuery(Name = "edit")]
    private int? EditingProductId { get; set; }

    private List<Product>? Products { get; set; }

    protected override async Task OnInitializedAsync()
    {
        Products = await InventoryService.GetAllAsync();
    }

    private async Task HandleAdd()
    {
        await InventoryService.AddAsync(NewProduct);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private async Task HandleSave(Product product)
    {
        await InventoryService.UpdateAsync(product);
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }

    private void HandleCancel()
    {
        Navigation.NavigateTo("/inventory", forceLoad: true);
    }
}

